25	//// Convolution Functions
26	
27	int32_t riscv_nn_conv_HWC_s16_s16_s16_sft_bias(const q15_t * in_tensor,
28	                            const uint16_t in_tensor_dim,
29	                            const uint16_t in_tensor_ch,
30	                            const q15_t * ker_weight,
31	                            const uint16_t out_tensor_ch,
32	                            const uint16_t ker_dim,
33	                            const uint16_t pad,
34	                            const uint16_t stride,
35	                            const q15_t * bias,
36	                            const uint16_t bias_lshift,
37	                            const uint16_t out_rshift,
38	                            q15_t * out_tensor,
39	                            const uint16_t out_tensor_dim,
40	                            q15_t * in_tmp_buf,
41	                            q7_t * tmp_buf)
42	{
43	#ifdef ENA_EMPTY_FUN
44	    //empty body
45	#elif (defined (ENA_VEC_ISA) || defined (ENA_DSP_ISA))
46	    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;
47	
48	    q15_t    *pBuffer = in_tmp_buf;
49	    q15_t    *pOut = out_tensor;
50	    q15_t    *im_buffer = in_tmp_buf;
51	    const q15_t *pA;
52	    int       i;
53	#if defined(ENA_VEC_ISA) && defined(ENA_VEC_INTRINSIC)
54	    long colCnt2 = in_tensor_ch * ker_dim * ker_dim;
55	    long vl;
56	#elif defined(ENA_VEC_ISA)
57	    uint16_t colCnt2 = in_tensor_ch * ker_dim * ker_dim;
58	    int32_t vl;
59	    NDS_VEC_VSETVLI_E16(vl, in_tensor_ch);
60	    NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   //for nn_set_zero_s8
61	#endif
62	
63	    /* This part implements the im2col function */
64	    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
65	    {
66	        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
67	        {
68	            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
69	            {
70	                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
71	                {
72	                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
73	                    {
74	                        /* Filling 0 for out-of-bound paddings */
75	                        nn_set_zero_s16(pBuffer, in_tensor_ch);
76	                    }
77	                    else
78	                    {
79	                        nn_dup_s16((q15_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
80	                    }
81	                    pBuffer += in_tensor_ch;
82	                }
83	            }
84	
85	#if defined(ENA_VEC_ISA) && defined(ENA_VEC_INTRINSIC)
86	            vl = __riscv_vsetvl_e32m8(colCnt2);
87	            pA = ker_weight;
88	            for (i = 0; i < out_tensor_ch; i++)
89	            {
90	                q31_t     sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
91	                q15_t    *pB = im_buffer;
92	
93	                //init
94	                vint32m1_t vsum = __riscv_vmv_v_x_i32m1(sum, vl);
95	                //clear v8~v15
96	                vint32m8_t vaccumulator = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
97	
98	                long colCnt = colCnt2;
99	                while (colCnt > 0)
100	                {
101	                    vl = __riscv_vsetvl_e16m4(colCnt);
102	                    //load src1
103	                    vint16m4_t vsrc1 = __riscv_vle16_v_i16m4(pA, vl);
104	                    //load src2
105	                    vint16m4_t vsrc2 = __riscv_vle16_v_i16m4(pB, vl);
106	                    //acc += src1 * src2
107	                    vaccumulator = __riscv_vwmacc(vaccumulator, vsrc2, vsrc1, vl);
108	                    //bump pointers and update loop counter
109	                    colCnt -= vl;
110	                    pA += vl;
111	                    pB += vl;
112	                }
113	                vl = __riscv_vsetvl_e32m8(colCnt2);     //note the avl here
114	                vsum = __riscv_vredsum(vaccumulator, vsum, vl);
115	                //move vr results to gpr;
116	                sum = __riscv_vmv_x(vsum);
117	                *pOut = (q15_t) NDS_ISA_SATS((sum >> out_rshift), 16);
118	                pOut++;
119	            }
120	#elif defined(ENA_VEC_ISA)
121	            NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
122	            pA = ker_weight;
123	            for (i = 0; i < out_tensor_ch; i++)
124	            {
125	                q31_t     sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
126	                q15_t    *pB = im_buffer;
127	
128	                //init
129	                NDS_VEC_VMV_S_X(NDS_VEC_V16, sum);
130	                //clear v8~v15
131	                NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);
132	
133	                uint16_t colCnt = colCnt2;
134	                while (colCnt > 0)
135	                {
136	                    NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
137	                    //load src1
138	                    NDS_VEC_VLH_V(NDS_VEC_V0, pA);
139	                    //load src2
140	                    NDS_VEC_VLH_V(NDS_VEC_V4, pB);
141	                    //acc += src1 * src2
142	                    NDS_VEC_VWMACC_VV(NDS_VEC_V8, NDS_VEC_V4, NDS_VEC_V0);
143	                    //bump pointers and update loop counter
144	                    colCnt -= vl;
145	                    pA += vl;
146	                    pB += vl;
147	                }
148	                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);     //note the avl here
149	                NDS_VEC_VREDSUM_VS(NDS_VEC_V16, NDS_VEC_V8, NDS_VEC_V16);
150	                //move vr results to gpr
151	                NDS_VEC_VMV_X_S(sum, NDS_VEC_V16);
152	                *pOut = (q15_t) NDS_ISA_SATS((sum >> out_rshift), 16);
153	                pOut++;
154	            }
155	#elif defined(ENA_DSP_ISA_64)
156	            pA = ker_weight;
157	            for (i = 0; i < out_tensor_ch; i++)
158	            {
159	                long     sum = (uint32_t)(((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift));
160	                q15_t    *pB = im_buffer;
161	
162	                uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim >> 3;
163	                while (colCnt)
164	                {
165	                    long     inA1 = *__SIMD64(pA)++;
166	                    long     inB1 = *__SIMD64(pB)++;
167	                    long     inA2 = *__SIMD64(pA)++;
168	                    long     inB2 = *__SIMD64(pB)++;
169	
170	                    sum = NDS_DSP_KMADA(sum, inA1, inB1);
171	                    sum = NDS_DSP_KMADA(sum, inA2, inB2);
172	
173	                    colCnt--;
174	                }
175	                //sum up the high and low part 32-bit results
176	                sum = (q31_t)NDS_DSP_CRSA32(sum, sum);
177	
178	                colCnt = in_tensor_ch * ker_dim * ker_dim & 0x7;
179	                while (colCnt)
180	                {
181	                    q15_t     inA1 = *pA++;
182	                    q15_t     inB1 = *pB++;
183	                    sum += inA1 * inB1;
184	                    colCnt--;
185	                }
186	                *pOut = (q15_t) NDS_DSP_SATS((sum >> out_rshift), 16);
187	                pOut++;
188	            }
189	#else
190	            pA = ker_weight;
191	            for (i = 0; i < out_tensor_ch; i++)
192	            {
193	                q31_t     sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
194	                q15_t    *pB = im_buffer;
195	
196	                uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim >> 2;
197	                while (colCnt)
198	                {
199	                    q31_t     inA1 = *__SIMD32(pA)++;
200	                    q31_t     inB1 = *__SIMD32(pB)++;
201	                    q31_t     inA2 = *__SIMD32(pA)++;
202	                    q31_t     inB2 = *__SIMD32(pB)++;
203	
204	                    sum = NDS_DSP_KMADA(sum, inA1, inB1);
205	                    sum = NDS_DSP_KMADA(sum, inA2, inB2);
206	
207	                    colCnt--;
208	                }
209	                colCnt = in_tensor_ch * ker_dim * ker_dim & 0x3;
210	                while (colCnt)
211	                {
212	                    q15_t     inA1 = *pA++;
213	                    q15_t     inB1 = *pB++;
214	                    sum += inA1 * inB1;
215	                    colCnt--;
216	                }
217	                *pOut = (q15_t) NDS_DSP_SATS((sum >> out_rshift), 16);
218	                pOut++;
219	            }
220	#endif
221	
222	            /* counter reset */
223	            pBuffer = im_buffer;
224	        }
225	    }
226	
227	#else
228	    uint16_t  i, j, k, l, m, n;
229	    int       conv_out;
230	    long in_row, in_col;
231	
232	    for (i = 0; i < out_tensor_ch; i++)
233	    {
234	        for (j = 0; j < out_tensor_dim; j++)
235	        {
236	            for (k = 0; k < out_tensor_dim; k++)
237	            {
238	                conv_out = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
239	                for (m = 0; m < ker_dim; m++)
240	                {
241	                    for (n = 0; n < ker_dim; n++)
242	                    {
243	                        in_row = stride * j + m - pad;
244	                        in_col = stride * k + n - pad;
245	                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim && in_col < in_tensor_dim)
246	                        {
247	                            for (l = 0; l < in_tensor_ch; l++)
248	                            {
249	                                conv_out +=
250	                                    in_tensor[(in_row * in_tensor_dim + in_col) * in_tensor_ch +
251	                                              l] * ker_weight[i * in_tensor_ch * ker_dim * ker_dim + (m * ker_dim +
252	                                                              n) * in_tensor_ch + l];
253	                            }
254	                        }
255	                    }
256	                }
257	                out_tensor[i + (j * out_tensor_dim + k) * out_tensor_ch] = (q15_t) NDS_ISA_SATS((conv_out >> out_rshift), 16);
258	            }
259	        }
260	    }
261	
262	#endif                          /* ENA_DSP_ISA */
263	
264	    return 0;
265	}
